/**
 * @summary List bills in a household
 */
export const getListBillsUrl = (
  householdId: number,
  params?: ListBillsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/households/${householdId}/bills?${stringifiedParams}`
    : `/api/households/${householdId}/bills`;
};

export const listBills = async (
  householdId: number,
  params?: ListBillsParams,
  options?: RequestInit,
): Promise<Bill[]> => {
  return customFetch<Bill[]>(getListBillsUrl(householdId, params), {
    ...options,
    method: "GET",
  });
};

